mapper.update:
UPDATE BOARD_TBL
SET
    BOARD_TITLE = #{boardTitle},
    BOARD_CONTENT = #{boardContent},
    BOARD_THUMB = #{boardThumb}
WHERE BOARD_NO = #{boardNo}

mapper.select:
SELECT COUNT(*)
FROM BOARD_TBL
WHERE BOARD_NO = #{boardNo}
AND WRITER_ID = #{writerId}

mapper.update:
UPDATE BOARD_TBL
SET READ_COUNT = NVL(READ_COUNT, 0) + 1
WHERE BOARD_NO = #{boardNo}

mapper.delete:
DELETE FROM BOARD_LIKE_TBL
WHERE BOARD_NO = #{boardNo}
AND MEMBER_ID = #{memberId}

mapper.select:
SELECT COUNT(*)
FROM BOARD_LIKE_TBL
WHERE BOARD_NO = #{boardNo}
AND MEMBER_ID = #{memberId}

mapper.update:
UPDATE BOARD_COMMENT_TBL
SET BOARD_COMMENT_CONTENT = #{content},
    UPDATED_AT = SYSDATE,
    IS_SECRET = #{isSecret}
WHERE BOARD_COMMENT_NO = #{commentNo}
  AND BOARD_COMMENT_WRITER = #{memberId}

mapper.delete:
DELETE FROM BOARD_COMMENT_TBL
WHERE BOARD_COMMENT_NO = #{commentNo}
  AND BOARD_COMMENT_WRITER = #{memberId}
